items.configValue:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "title": "OrderList",
  "description": "A list of commerce orders generated by AI.",
  "type": "object",
  "properties": {
    "orders": {
      "type": "array",
      "description": "An array of generated order objects.",
      "items": {
        "title": "Order",
        "type": "object",
        "properties": {
          "accountId": {
            "description": "The ID of the account that placed the order.",
            "type": "string"
          },
          "orderStatus": {
            "description": "The numeric status of the order (e.g., 0 for pending, 1 for processing).",
            "type": "number"
          },
          "externalReferenceCode": {
            "description": "A unique identifier for the order.",
            "type": "string"
          },
          "items": {
            "description": "The items included in the order.",
            "type": "array",
            "items": {
              "type": "object",
              "properties": {
                "sku": {
                  "description": "The SKU of the product.",
                  "type": "string"
                },
                "quantity": {
                  "description": "The quantity of the product.",
                  "type": "integer",
                  "minimum": 1
                }
              },
              "required": [
                "sku",
                "quantity"
              ]
            }
          }
        },
        "required": [
          "accountId",
          "items",
          "externalReferenceCode"
        ]
      }
    }
  },
  "required": ["orders"]
}
